mapper.select:
SELECT r.*, l.name AS lab_name, u.username, u.real_name FROM reservation r LEFT JOIN `lab` l ON l.id = r.lab_id LEFT JOIN `user` u ON u.id = r.user_id
AND r.status = #{status}
AND ( u.real_name LIKE CONCAT('%', #{keyword}, '%') OR u.username LIKE CONCAT('%', #{keyword}, '%') OR l.name LIKE CONCAT('%', #{keyword}, '%') OR r.title LIKE CONCAT('%', #{keyword}, '%') )
AND r.start_time >= #{startTime} AND r.start_time <= #{endTime}
ORDER BY r.create_time DESC

SELECT * FROM reservation
WHERE lab_id = #{labId}
  AND status IN (0, 1)
  AND start_time < #{endTime}
  AND end_time > #{startTime}

SELECT COUNT(*) FROM reservation
WHERE lab_id = #{labId}
  AND status IN (0, 1)
  AND start_time < #{endTime}
  AND end_time > #{startTime}

      AND id != #{excludeId}

mapper.update:
UPDATE reservation
SET status = #{status}
, reject_reason = #{rejectReason}
WHERE id = #{id}
